(1, '～ましょうか', '~mashou ka', 'haruskah saya ~?', 'Menawarkan bantuan atau bertanya tentang ajakan.', ARRAY['ajakan','tawaran']::text[], '[{"sentence":"手伝いましょうか。","hiragana":"てつだいましょうか。","meaning":"Mau saya bantu?"},{"sentence":"窓を開けましょうか。","hiragana":"まどをあけましょうか。","meaning":"Saya buka jendelanya?"}]'::jsonb, 28),
(1, 'Verb-たい', '~tai', 'ingin ~', 'Menyatakan keinginan pembicara untuk melakukan sesuatu.', ARRAY['keinginan']::text[], '[{"sentence":"日本へ行きたいです。","hiragana":"にほんへいきたいです。","meaning":"Saya ingin pergi ke Jepang."},{"sentence":"何が食べたいですか。","hiragana":"なにがたべたいですか。","meaning":"Ingin makan apa?"}]'::jsonb, 29),
(1, '～が欲しいです', '~ga hoshii desu', 'ingin (memiliki) ~', 'Menyatakan keinginan memiliki suatu benda.', ARRAY['keinginan']::text[], '[{"sentence":"新しい車が欲しいです。","hiragana":"あたらしいくるまがほしいです。","meaning":"Saya ingin mobil baru."},{"sentence":"何が欲しいですか。","hiragana":"なにがほしいですか。","meaning":"Ingin apa?"}]'::jsonb, 30),
