(1, '～ないほうがいいです', '~nai hou ga ii desu', 'sebaiknya jangan ~', 'Saran untuk tidak melakukan sesuatu.', ARRAY['saran','negatif']::text[], '[{"sentence":"無理しないほうがいいです。","hiragana":"むりしないほうがいいです。","meaning":"Sebaiknya jangan memaksakan diri."},{"sentence":"そこへ行かないほうがいいです。","hiragana":"そこへいかないほうがいいです。","meaning":"Sebaiknya jangan ke sana."}]'::jsonb, 107),
(1, '～なければなりません', '~nakereba narimasen', 'harus ~', 'Menyatakan kewajiban.', ARRAY['kewajiban']::text[], '[{"sentence":"宿題をしなければなりません。","hiragana":"しゅくだいをしなければなりません。","meaning":"Harus mengerjakan PR."},{"sentence":"明日早く起きなければなりません。","hiragana":"あしたはやくおきなければなりません。","meaning":"Besok harus bangun pagi."}]'::jsonb, 108),
(1, '～なくてもいいです', '~nakute mo ii desu', 'tidak perlu ~', 'Menyatakan ketiadaan kewajiban.', ARRAY['izin','negatif']::text[], '[{"sentence":"来なくてもいいです。","hiragana":"こなくてもいいです。","meaning":"Tidak perlu datang."},{"sentence":"全部食べなくてもいいです。","hiragana":"ぜんぶたべなくてもいいです。","meaning":"Tidak perlu habiskan semua."}]'::jsonb, 109),
(1, '～てはいけません', '~te wa ikemasen', 'tidak boleh ~', 'Menyatakan larangan.', ARRAY['larangan']::text[], '[{"sentence":"ここでタバコを吸ってはいけません。","hiragana":"ここでたばこをすってはいけません。","meaning":"Tidak boleh merokok di sini."},{"sentence":"遅れてはいけません。","hiragana":"おくれてはいけません。","meaning":"Tidak boleh terlambat."}]'::jsonb, 110),
(1, 'Verb-てみる', '~te miru', 'mencoba ~', 'Melakukan sesuatu untuk mencoba.', ARRAY['percobaan']::text[], '[{"sentence":"この服を着てみます。","hiragana":"このふくをきてみます。","meaning":"Mencoba baju ini."},{"sentence":"一度食べてみてください。","hiragana":"いちどたべてみてください。","meaning":"Coba makan sekali."}]'::jsonb, 111),
(1, '～でしょう (cuaca)', '~deshou', 'akan ~ (prakiraan)', 'Sering dipakai untuk prakiraan cuaca.', ARRAY['prakiraan']::text[], '[{"sentence":"明日は曇りでしょう。","hiragana":"あしたはくもりでしょう。","meaning":"Besok mungkin berawan."},{"sentence":"午後は晴れるでしょう。","hiragana":"ごごははれるでしょう。","meaning":"Sore mungkin cerah."}]'::jsonb, 112),
(1, '～と一緒に', '~to issho ni', 'bersama dengan ~', 'Menyatakan melakukan sesuatu bersama orang.', ARRAY['kebersamaan']::text[], '[{"sentence":"家族と一緒に住んでいます。","hiragana":"かぞくといっしょにすんでいます。","meaning":"Tinggal bersama keluarga."},{"sentence":"友達と一緒に映画を見ました。","hiragana":"ともだちといっしょにえいがをみました。","meaning":"Nonton film bersama teman."}]'::jsonb, 113),
(1, '～がわかります', '~ga wakarimasu', 'mengerti ~', 'Menyatakan pemahaman; objek pakai が.', ARRAY['pemahaman']::text[], '[{"sentence":"日本語がわかります。","hiragana":"にほんごがわかります。","meaning":"Mengerti bahasa Jepang."},{"sentence":"意味がわかりません。","hiragana":"いみがわかりません。","meaning":"Tidak mengerti artinya."}]'::jsonb, 114),
(1, '～に乗ります', '~ni norimasu', 'naik ~ (kendaraan)', 'Naik kendaraan memakai partikel に.', ARRAY['transportasi']::text[], '[{"sentence":"電車に乗ります。","hiragana":"でんしゃにのります。","meaning":"Naik kereta."},{"sentence":"タクシーに乗りましょう。","hiragana":"たくしーにのりましょう。","meaning":"Ayo naik taksi."}]'::jsonb, 115),
(1, '～を降ります', '~wo orimasu', 'turun dari ~', 'Turun dari kendaraan memakai partikel を.', ARRAY['transportasi']::text[], '[{"sentence":"次の駅で電車を降ります。","hiragana":"つぎのえきででんしゃをおります。","meaning":"Turun dari kereta di stasiun berikutnya."},{"sentence":"ここでバスを降ります。","hiragana":"ここでばすをおります。","meaning":"Turun bus di sini."}]'::jsonb, 116),
(1, '～に会います', '~ni aimasu', 'bertemu dengan ~', 'Bertemu seseorang memakai partikel に.', ARRAY['interaksi']::text[], '[{"sentence":"友達に会います。","hiragana":"ともだちにあいます。","meaning":"Bertemu teman."},{"sentence":"駅で先生に会いました。","hiragana":"えきでせんせいにあいました。","meaning":"Bertemu guru di stasiun."}]'::jsonb, 117),
(1, '～がいい', '~ga ii', '~ yang bagus / mau ~', 'Menyatakan preferensi/pilihan terbaik.', ARRAY['pilihan']::text[], '[{"sentence":"これがいいです。","hiragana":"これがいいです。","meaning":"Yang ini bagus."},{"sentence":"お茶がいいです。","hiragana":"おちゃがいいです。","meaning":"Mau teh saja."}]'::jsonb, 118),
(1, 'Verb-ましょう (kepastian)', '~mashou', 'mari kita ~', 'Ungkapan untuk memutuskan tindakan bersama.', ARRAY['ajakan']::text[], '[{"sentence":"そろそろ始めましょう。","hiragana":"そろそろはじめましょう。","meaning":"Mari kita mulai."},{"sentence":"ここで待ちましょう。","hiragana":"ここでまちましょう。","meaning":"Mari tunggu di sini."}]'::jsonb, 119),
(1, '～について', '~ni tsuite', 'tentang ~', 'Menyatakan topik pembahasan.', ARRAY['topik']::text[], '[{"sentence":"日本の文化について話します。","hiragana":"にほんのぶんかについてはなします。","meaning":"Berbicara tentang budaya Jepang."},{"sentence":"この問題について考えます。","hiragana":"このもんだいについてかんがえます。","meaning":"Memikirkan tentang masalah ini."}]'::jsonb, 120),
(1, '～でいちばん', '~de ichiban', 'paling ~ di ~', 'Superlatif dalam suatu lingkup/tempat.', ARRAY['superlatif']::text[], '[{"sentence":"世界で一番高い山。","hiragana":"せかいでいちばんたかいやま。","meaning":"Gunung tertinggi di dunia."},{"sentence":"クラスで一番頭がいいです。","hiragana":"くらすでいちばんあたまがいいです。","meaning":"Paling pintar di kelas."}]'::jsonb, 121),
(1, '～と同じ', '~to onaji', 'sama dengan ~', 'Menyatakan kesamaan.', ARRAY['perbandingan']::text[], '[{"sentence":"私のと同じです。","hiragana":"わたしのとおなじです。","meaning":"Sama dengan punya saya."},{"sentence":"彼と同じ年です。","hiragana":"かれとおなじとしです。","meaning":"Seumuran dengan dia."}]'::jsonb, 122),
(1, 'Verb-た後で', '~ta ato de', 'setelah ~ (kata kerja)', 'Urutan: setelah aksi A, baru B (versi kata kerja).', ARRAY['urutan']::text[], '[{"sentence":"食べた後で歯を磨きます。","hiragana":"たべたあとではをみがきます。","meaning":"Setelah makan sikat gigi."},{"sentence":"仕事をした後で休みます。","hiragana":"しごとをしたあとでやすみます。","meaning":"Setelah kerja istirahat."}]'::jsonb, 123),
(1, '～ても', '~te mo', 'meskipun ~', 'Menyatakan pengandaian "meskipun".', ARRAY['pengandaian']::text[], '[{"sentence":"雨が降っても行きます。","hiragana":"あめがふってもいきます。","meaning":"Meskipun hujan tetap pergi."},{"sentence":"高くても買います。","hiragana":"たかくてもかいます。","meaning":"Meskipun mahal tetap beli."}]'::jsonb, 124),
(1, '～たら (kalau)', '~tara', 'kalau/jika ~', 'Pengandaian kondisional dasar.', ARRAY['pengandaian']::text[], '[{"sentence":"お金があったら、旅行します。","hiragana":"おかねがあったら、りょこうします。","meaning":"Kalau ada uang, jalan-jalan."},{"sentence":"駅に着いたら、電話してください。","hiragana":"えきについたら、でんわしてください。","meaning":"Kalau sampai stasiun, tolong telepon."}]'::jsonb, 125),
(1, 'Verb-ながら (sambil)', '~nagara', 'sambil ~', 'Dua aktivitas bersamaan (utama yang kedua).', ARRAY['aksi-ganda']::text[], '[{"sentence":"テレビを見ながらご飯を食べます。","hiragana":"てれびをみながらごはんをたべます。","meaning":"Makan sambil nonton TV."},{"sentence":"コーヒーを飲みながら話しましょう。","hiragana":"こーひーをのみながらはなしましょう。","meaning":"Ayo bicara sambil minum kopi."}]'::jsonb, 126),
(1, 'お～ください', 'o~kudasai', 'silakan ~ (sopan)', 'Bentuk permintaan sopan (keigo dasar).', ARRAY['sopan','permintaan']::text[], '[{"sentence":"お入りください。","hiragana":"おはいりください。","meaning":"Silakan masuk."},{"sentence":"お待ちください。","hiragana":"おまちください。","meaning":"Silakan tunggu."}]'::jsonb, 127),
(1, '～でございます', '~de gozaimasu', 'adalah ~ (sangat sopan)', 'Bentuk です yang sangat sopan.', ARRAY['sopan','copula']::text[], '[{"sentence":"受付はこちらでございます。","hiragana":"うけつけはこちらでございます。","meaning":"Resepsionis di sebelah sini."},{"sentence":"以上でございます。","hiragana":"いじょうでございます。","meaning":"Sekian."}]'::jsonb, 128),
(1, '～ました/～ています (perfektif)', '~te imasu', 'sudah dalam keadaan ~', '～ています bisa menyatakan hasil keadaan setelah aksi.', ARRAY['aspek']::text[], '[{"sentence":"結婚しています。","hiragana":"けっこんしています。","meaning":"Sudah menikah."},{"sentence":"窓が開いています。","hiragana":"まどがあいています。","meaning":"Jendelanya terbuka."}]'::jsonb, 129),
(1, '～でも～でも', '~demo ~demo', 'baik ~ maupun ~', 'Menyebut pilihan yang setara.', ARRAY['pilihan']::text[], '[{"sentence":"コーヒーでもお茶でもいいです。","hiragana":"こーひーでもおちゃでもいいです。","meaning":"Kopi atau teh sama saja."},{"sentence":"いつでもどこでも大丈夫です。","hiragana":"いつでもどこでもだいじょうぶです。","meaning":"Kapan pun di mana pun tidak apa-apa."}]'::jsonb, 130),
(1, '疑問詞 + も + 否定', '~mo ~nai', 'tidak ada ~ pun', 'Kata tanya + も + negatif = "tidak ~ pun".', ARRAY['negatif']::text[], '[{"sentence":"何も食べませんでした。","hiragana":"なにもたべませんでした。","meaning":"Tidak makan apa-apa."},{"sentence":"誰もいません。","hiragana":"だれもいません。","meaning":"Tidak ada siapa-siapa."}]'::jsonb, 131),
(1, '疑問詞 + か', '~ka', 'sesuatu/seseorang', 'Kata tanya + か = bentuk tak tentu (sesuatu/seseorang).', ARRAY['tak-tentu']::text[], '[{"sentence":"何か飲みますか。","hiragana":"なにかのみますか。","meaning":"Mau minum sesuatu?"},{"sentence":"誰か来ましたか。","hiragana":"だれかきましたか。","meaning":"Ada yang datang?"}]'::jsonb, 132),
(1, '～でしょう？ (intonasi naik)', '~deshou?', 'iya kan?', 'Mencari persetujuan dengan intonasi naik.', ARRAY['konfirmasi']::text[], '[{"sentence":"これでいいでしょう？","hiragana":"これでいいでしょう？","meaning":"Ini sudah cukup kan?"},{"sentence":"面白いでしょう？","hiragana":"おもしろいでしょう？","meaning":"Menarik kan?"}]'::jsonb, 133),
(1, '～時間/～分 (durasi)', '~jikan / ~fun', 'selama ~ jam/menit', 'Menyatakan durasi waktu.', ARRAY['durasi']::text[], '[{"sentence":"二時間勉強しました。","hiragana":"にじかんべんきょうしました。","meaning":"Belajar selama 2 jam."},{"sentence":"十分待ちました。","hiragana":"じゅっぷんまちました。","meaning":"Menunggu 10 menit."}]'::jsonb, 134),
(1, '～回 (frekuensi)', '~kai', '~ kali', 'Menyatakan frekuensi.', ARRAY['frekuensi']::text[], '[{"sentence":"一日に三回食べます。","hiragana":"いちにちにさんかいたべます。","meaning":"Makan 3 kali sehari."},{"sentence":"週に二回運動します。","hiragana":"しゅうににかいうんどうします。","meaning":"Olahraga 2 kali seminggu."}]'::jsonb, 135),
(1, 'まだ + 肯定', 'mada', 'masih (positif)', 'Menyatakan keadaan yang masih berlangsung.', ARRAY['aspek']::text[], '[{"sentence":"まだ雨が降っています。","hiragana":"まだあめがふっています。","meaning":"Masih hujan."},{"sentence":"まだあります。","hiragana":"まだあります。","meaning":"Masih ada."}]'::jsonb, 136),
(1, '～ことがあります (kadang)', '~koto ga arimasu', 'kadang ~', 'Bentuk biasa menyatakan kejadian sesekali.', ARRAY['frekuensi']::text[], '[{"sentence":"時々遅れることがあります。","hiragana":"ときどきおくれることがあります。","meaning":"Kadang terlambat."},{"sentence":"朝ご飯を食べないことがあります。","hiragana":"あさごはんをたべないことがあります。","meaning":"Kadang tidak sarapan."}]'::jsonb, 137),
(1, '～でしょう (dugaan kuat)', '~deshou', 'pasti/mungkin ~', 'Dugaan berdasar perkiraan.', ARRAY['dugaan']::text[], '[{"sentence":"彼はもう着いたでしょう。","hiragana":"かれはもうついたでしょう。","meaning":"Dia mungkin sudah sampai."},{"sentence":"難しいでしょう。","hiragana":"むずかしいでしょう。","meaning":"Mungkin sulit."}]'::jsonb, 138),
(1, '～と (penghubung benda)', '~to', 'dan (benda)', 'Menggabungkan kata benda secara lengkap.', ARRAY['partikel']::text[], '[{"sentence":"犬と猫がいます。","hiragana":"いぬとねこがいます。","meaning":"Ada anjing dan kucing."},{"sentence":"母と父と一緒に行きます。","hiragana":"ははとちちといっしょにいきます。","meaning":"Pergi bersama ibu dan ayah."}]'::jsonb, 139),
(1, 'Verb-ましょうか (konfirmasi rencana)', '~mashou ka', 'bagaimana kalau kita ~?', 'Mengusulkan rencana dan minta persetujuan.', ARRAY['ajakan']::text[], '[{"sentence":"そろそろ出かけましょうか。","hiragana":"そろそろでかけましょうか。","meaning":"Bagaimana kalau kita berangkat?"},{"sentence":"昼ご飯を食べましょうか。","hiragana":"ひるごはんをたべましょうか。","meaning":"Bagaimana kalau makan siang?"}]'::jsonb, 140),
(1, '～ですが (pembuka sopan)', '~desu ga', 'permisi, ~', 'Pembuka sopan sebelum permintaan/pertanyaan.', ARRAY['sopan','pembuka']::text[], '[{"sentence":"すみませんが、道を教えてください。","hiragana":"すみませんが、みちをおしえてください。","meaning":"Maaf, tolong tunjukkan jalan."},{"sentence":"失礼ですが、お名前は？","hiragana":"しつれいですが、おなまえは？","meaning":"Maaf, siapa nama Anda?"}]'::jsonb, 141),
(1, '～にします (keputusan minuman)', '~ni shimasu', 'saya ambil ~', 'Khusus saat memesan/memilih.', ARRAY['keputusan']::text[], '[{"sentence":"私はラーメンにします。","hiragana":"わたしはらーめんにします。","meaning":"Saya pesan ramen."},{"sentence":"赤いのにします。","hiragana":"あかいのにします。","meaning":"Saya pilih yang merah."}]'::jsonb, 142),
(1, 'Verb-ています (progres berkelanjutan)', '~te imasu', 'terus ~', 'Menyatakan aksi yang berlangsung terus-menerus.', ARRAY['progresif']::text[], '[{"sentence":"ずっと考えています。","hiragana":"ずっとかんがえています。","meaning":"Terus memikirkan."},{"sentence":"今探しています。","hiragana":"いまさがしています。","meaning":"Sedang mencari."}]'::jsonb, 143),
(1, '～でも (ajakan ringan)', '~demo', '~ atau semacamnya', 'Mengajak dengan nada ringan/tidak memaksa.', ARRAY['ajakan']::text[], '[{"sentence":"映画でも見ませんか。","hiragana":"えいがでもみませんか。","meaning":"Bagaimana kalau nonton film atau apa?"},{"sentence":"散歩でもしましょう。","hiragana":"さんぽでもしましょう。","meaning":"Ayo jalan-jalan saja."}]'::jsonb, 144),
(1, 'とても/あまり', 'totemo / amari', 'sangat / tidak terlalu', 'Adverbia derajat; あまり dengan negatif.', ARRAY['adverbia']::text[], '[{"sentence":"とても面白いです。","hiragana":"とてもおもしろいです。","meaning":"Sangat menarik."},{"sentence":"あまり好きではありません。","hiragana":"あまりすきではありません。","meaning":"Tidak terlalu suka."}]'::jsonb, 145),
(1, 'よく/たまに/時々', 'yoku / tamani / tokidoki', 'sering / jarang / kadang', 'Adverbia frekuensi.', ARRAY['adverbia','frekuensi']::text[], '[{"sentence":"よく映画を見ます。","hiragana":"よくえいがをみます。","meaning":"Sering nonton film."},{"sentence":"時々料理をします。","hiragana":"ときどきりょうりをします。","meaning":"Kadang memasak."}]'::jsonb, 146);
INSERT INTO public.grammar (level_id, pattern, reading, meaning, explanation, tags, examples, order_index) VALUES
(2, '～ている (keadaan/progres)', '~te iru', 'sedang/keadaan ~', 'Aksi berlangsung atau keadaan akibat aksi.', ARRAY['te-form','progresif']::text[], '[{"sentence":"今、ご飯を食べている。","hiragana":"いま、ごはんをたべている。","meaning":"Sekarang sedang makan."},{"sentence":"窓が開いている。","hiragana":"まどがあいている。","meaning":"Jendelanya terbuka."}]'::jsonb, 1),
(2, '～てある', '~te aru', 'telah di~ (keadaan akibat)', 'Keadaan hasil aksi yang sengaja dilakukan (transitif).', ARRAY['te-form','keadaan']::text[], '[{"sentence":"壁に絵がかけてある。","hiragana":"かべにえがかけてある。","meaning":"Di dinding tergantung lukisan."},{"sentence":"ドアが閉めてある。","hiragana":"どあがしめてある。","meaning":"Pintunya (sudah) ditutup."}]'::jsonb, 2),
(2, '～てしまう', '~te shimau', '~ (selesai/terlanjur)', 'Menyatakan penyelesaian total atau penyesalan.', ARRAY['te-form','aspek']::text[], '[{"sentence":"宿題を全部やってしまった。","hiragana":"しゅくだいをぜんぶやってしまった。","meaning":"PR-nya selesai semua."},{"sentence":"電車に傘を忘れてしまった。","hiragana":"でんしゃにかさをわすれてしまった。","meaning":"Terlanjur ketinggalan payung di kereta."}]'::jsonb, 3),
(2, '～ておく', '~te oku', '~ untuk persiapan', 'Melakukan sesuatu sebelumnya sebagai persiapan.', ARRAY['te-form','persiapan']::text[], '[{"sentence":"旅行の前にホテルを予約しておく。","hiragana":"りょこうのまえにほてるをよやくしておく。","meaning":"Pesan hotel dulu sebelum perjalanan."},{"sentence":"ビールを冷やしておきます。","hiragana":"びーるをひやしておきます。","meaning":"Saya dinginkan birnya dulu."}]'::jsonb, 4),
(2, '～てみる', '~te miru', 'mencoba ~', 'Melakukan sesuatu untuk mencoba.', ARRAY['te-form','percobaan']::text[], '[{"sentence":"新しいレストランに行ってみる。","hiragana":"あたらしいれすとらんにいってみる。","meaning":"Coba pergi ke restoran baru."},{"sentence":"この服を着てみてもいいですか。","hiragana":"このふくをきてみてもいいですか。","meaning":"Boleh coba pakai baju ini?"}]'::jsonb, 5),
(2, '～てくれる', '~te kureru', 'melakukan ~ untuk saya', 'Orang lain melakukan sesuatu untuk pembicara.', ARRAY['te-form','memberi']::text[], '[{"sentence":"友達が手伝ってくれた。","hiragana":"ともだちがてつだってくれた。","meaning":"Teman membantu saya."},{"sentence":"母がお弁当を作ってくれた。","hiragana":"はははおべんとうをつくってくれた。","meaning":"Ibu membuatkan bekal."}]'::jsonb, 6),
(2, '～てあげる', '~te ageru', 'melakukan ~ untuk orang lain', 'Pembicara melakukan sesuatu untuk orang lain.', ARRAY['te-form','memberi']::text[], '[{"sentence":"友達に本を貸してあげた。","hiragana":"ともだちにほんをかしてあげた。","meaning":"Meminjamkan buku ke teman."},{"sentence":"妹に料理を作ってあげる。","hiragana":"いもうとにりょうりをつくってあげる。","meaning":"Membuatkan masakan untuk adik."}]'::jsonb, 7),
(2, '～てもらう', '~te morau', 'minta dilakukan ~', 'Menerima jasa/tindakan dari orang lain.', ARRAY['te-form','menerima']::text[], '[{"sentence":"先生に説明してもらった。","hiragana":"せんせいにせつめいしてもらった。","meaning":"Dijelaskan oleh guru."},{"sentence":"友達に駅まで送ってもらった。","hiragana":"ともだちにえきまでおくってもらった。","meaning":"Diantar teman ke stasiun."}]'::jsonb, 8),
