(2, 'お／ご～になる (尊敬)', 'o/go ~ni naru', 'melakukan ~ (menghormati)', 'Bentuk menghormati lawan bicara (sonkeigo dasar).', ARRAY['sopan']::text[], '[{"sentence":"先生はもうお帰りになりました。","hiragana":"せんせいはもうおかえりになりました。","meaning":"Pak Guru sudah pulang."},{"sentence":"お客様がお待ちになっています。","hiragana":"おきゃくさまがおまちになっています。","meaning":"Tamu sedang menunggu."}]'::jsonb, 109),
(2, '～ていく', '~te iku', '~ menjauh/seterusnya', 'Aksi yang berlanjut menjauh atau ke depan.', ARRAY['aspek']::text[], '[{"sentence":"これからも頑張っていきます。","hiragana":"これからもがんばっていきます。","meaning":"Akan terus berusaha ke depannya."},{"sentence":"鳥が飛んでいった。","hiragana":"とりがとんでいった。","meaning":"Burung terbang menjauh."}]'::jsonb, 110),
(2, '～てくる', '~te kuru', '~ mendekat/mulai', 'Aksi yang mendekat atau mulai muncul.', ARRAY['aspek']::text[], '[{"sentence":"だんだん寒くなってきた。","hiragana":"だんだんさむくなってきた。","meaning":"Lama-lama jadi dingin."},{"sentence":"雨が降ってきた。","hiragana":"あめがふってきた。","meaning":"Hujan mulai turun."}]'::jsonb, 111),
(2, '～ば～ほど (derajat)', '~ba ~hodo', 'makin ~ makin ~', 'Hubungan proporsional (variasi).', ARRAY['perbandingan']::text[], '[{"sentence":"見れば見るほど好きになる。","hiragana":"みればみるほどすきになる。","meaning":"Makin dilihat makin suka."},{"sentence":"読めば読むほど面白い。","hiragana":"よめばよむほどおもしろい。","meaning":"Makin dibaca makin menarik."}]'::jsonb, 112),
(2, '～ないと', '~nai to', 'kalau tidak ~ (harus)', 'Menyatakan keharusan secara informal.', ARRAY['kewajiban']::text[], '[{"sentence":"早く行かないと。","hiragana":"はやくいかないと。","meaning":"Harus segera pergi."},{"sentence":"勉強しないと、試験に落ちる。","hiragana":"べんきょうしないと、しけんにおちる。","meaning":"Kalau tidak belajar, gagal ujian."}]'::jsonb, 113),
(2, '～ばかり (jumlah)', '~bakari', 'kira-kira/hanya ~', 'Menyatakan perkiraan jumlah atau "hanya".', ARRAY['perkiraan']::text[], '[{"sentence":"三日ばかり旅行した。","hiragana":"みっかばかりりょこうした。","meaning":"Bepergian sekitar 3 hari."},{"sentence":"若い人ばかりだ。","hiragana":"わかいひとばかりだ。","meaning":"Isinya orang muda semua."}]'::jsonb, 114),
(2, '～最中に', '~saichuu ni', 'sedang asyik ~', 'Tepat saat suatu aksi berlangsung.', ARRAY['waktu']::text[], '[{"sentence":"食事の最中に電話が鳴った。","hiragana":"しょくじのさいちゅうにでんわがなった。","meaning":"Saat sedang makan, telepon berbunyi."},{"sentence":"会議の最中に地震があった。","hiragana":"かいぎのさいちゅうにじしんがあった。","meaning":"Saat rapat berlangsung, ada gempa."}]'::jsonb, 115);
INSERT INTO public.grammar (level_id, pattern, reading, meaning, explanation, tags, examples, order_index) VALUES
(1, '～は～です', '~wa ~desu', '~ adalah ~', 'Pola dasar menyatakan identitas/keadaan. は partikel topik, です kopula sopan.', ARRAY['copula','dasar']::text[], '[{"sentence":"私は学生です。","hiragana":"わたしはがくせいです。","meaning":"Saya adalah pelajar."},{"sentence":"これは本です。","hiragana":"これはほんです。","meaning":"Ini adalah buku."}]'::jsonb, 1),
(1, '～は～ではありません', '~wa ~dewa arimasen', '~ bukan ~', 'Bentuk negatif dari ～です. Dalam percakapan sering jadi ～じゃありません.', ARRAY['copula','negatif']::text[], '[{"sentence":"私は先生ではありません。","hiragana":"わたしはせんせいではありません。","meaning":"Saya bukan guru."},{"sentence":"それは私のじゃありません。","hiragana":"それはわたしのじゃありません。","meaning":"Itu bukan milik saya."}]'::jsonb, 2),
(1, '～ですか', '~desu ka', 'Apakah ~?', 'Partikel か di akhir kalimat menjadikannya pertanyaan.', ARRAY['pertanyaan']::text[], '[{"sentence":"あなたは学生ですか。","hiragana":"あなたはがくせいですか。","meaning":"Apakah kamu pelajar?"},{"sentence":"これはペンですか。","hiragana":"これはぺんですか。","meaning":"Apakah ini pena?"}]'::jsonb, 3),
(1, '～も', '~mo', 'juga', 'Menggantikan は/が untuk menyatakan "juga".', ARRAY['partikel']::text[], '[{"sentence":"私も行きます。","hiragana":"わたしもいきます。","meaning":"Saya juga pergi."},{"sentence":"これもください。","hiragana":"これもください。","meaning":"Ini juga, tolong."}]'::jsonb, 4),
(1, '～の (kepemilikan)', '~no', 'milik ~ / ~ dari', 'Menghubungkan dua kata benda: kepemilikan atau atribut.', ARRAY['partikel']::text[], '[{"sentence":"私の本です。","hiragana":"わたしのほんです。","meaning":"Ini buku saya."},{"sentence":"日本語の先生。","hiragana":"にほんごのせんせい。","meaning":"Guru bahasa Jepang."}]'::jsonb, 5),
(1, '～が (subjek)', '~ga', 'partikel subjek', 'Menandai subjek, terutama informasi baru atau penekanan.', ARRAY['partikel']::text[], '[{"sentence":"猫がいます。","hiragana":"ねこがいます。","meaning":"Ada kucing."},{"sentence":"誰が来ましたか。","hiragana":"だれがきましたか。","meaning":"Siapa yang datang?"}]'::jsonb, 6),
(1, '～を (objek)', '~wo', 'partikel objek', 'Menandai objek langsung dari kata kerja transitif.', ARRAY['partikel']::text[], '[{"sentence":"ご飯を食べます。","hiragana":"ごはんをたべます。","meaning":"Makan nasi."},{"sentence":"本を読みます。","hiragana":"ほんをよみます。","meaning":"Membaca buku."}]'::jsonb, 7),
(1, '～に (waktu)', '~ni', 'pada (waktu)', 'Menunjukkan titik waktu spesifik.', ARRAY['partikel','waktu']::text[], '[{"sentence":"七時に起きます。","hiragana":"しちじにおきます。","meaning":"Bangun jam tujuh."},{"sentence":"日曜日に休みます。","hiragana":"にちようびにやすみます。","meaning":"Libur pada hari Minggu."}]'::jsonb, 8),
(1, '～に (tujuan)', '~ni', 'ke (tujuan)', 'Menunjukkan arah/tujuan dengan kata kerja gerak.', ARRAY['partikel','gerak']::text[], '[{"sentence":"学校に行きます。","hiragana":"がっこうにいきます。","meaning":"Pergi ke sekolah."},{"sentence":"日本に来ました。","hiragana":"にほんにきました。","meaning":"Datang ke Jepang."}]'::jsonb, 9),
(1, '～へ', '~e', 'ke (arah)', 'Menunjukkan arah pergerakan. Ditulis へ dibaca "e".', ARRAY['partikel','gerak']::text[], '[{"sentence":"東京へ行きます。","hiragana":"とうきょうへいきます。","meaning":"Pergi ke Tokyo."},{"sentence":"家へ帰ります。","hiragana":"いえへかえります。","meaning":"Pulang ke rumah."}]'::jsonb, 10),
(1, '～で (tempat)', '~de', 'di (tempat aktivitas)', 'Menunjukkan tempat terjadinya suatu aktivitas.', ARRAY['partikel','tempat']::text[], '[{"sentence":"図書館で勉強します。","hiragana":"としょかんでべんきょうします。","meaning":"Belajar di perpustakaan."},{"sentence":"レストランで食べます。","hiragana":"れすとらんでたべます。","meaning":"Makan di restoran."}]'::jsonb, 11),
(1, '～で (alat/cara)', '~de', 'dengan (alat/cara)', 'Menunjukkan alat atau cara melakukan sesuatu.', ARRAY['partikel','cara']::text[], '[{"sentence":"バスで行きます。","hiragana":"ばすでいきます。","meaning":"Pergi dengan bus."},{"sentence":"箸で食べます。","hiragana":"はしでたべます。","meaning":"Makan dengan sumpit."}]'::jsonb, 12),
(1, '～と (bersama)', '~to', 'dengan / dan', 'Menyatakan "bersama seseorang" atau menggabungkan kata benda.', ARRAY['partikel']::text[], '[{"sentence":"友達と行きます。","hiragana":"ともだちといきます。","meaning":"Pergi dengan teman."},{"sentence":"パンと卵を買います。","hiragana":"ぱんとたまごをかいます。","meaning":"Beli roti dan telur."}]'::jsonb, 13),
(1, '～から～まで', '~kara ~made', 'dari ~ sampai ~', 'Menunjukkan rentang waktu atau tempat.', ARRAY['partikel','waktu']::text[], '[{"sentence":"九時から五時まで働きます。","hiragana":"くじからごじまではたらきます。","meaning":"Bekerja dari jam 9 sampai jam 5."},{"sentence":"駅から家まで歩きます。","hiragana":"えきからいえまであるきます。","meaning":"Jalan dari stasiun ke rumah."}]'::jsonb, 14),
(1, '～や～など', '~ya ~nado', '~, ~, dan lain-lain', 'Menyebut beberapa contoh dari kumpulan yang lebih besar.', ARRAY['partikel','contoh']::text[], '[{"sentence":"本やノートを買いました。","hiragana":"ほんやのーとをかいました。","meaning":"Beli buku, buku catatan, dll."},{"sentence":"東京や大阪などに行きました。","hiragana":"とうきょうやおおさかなどにいきました。","meaning":"Pergi ke Tokyo, Osaka, dll."}]'::jsonb, 15),
(1, '～ね', '~ne', 'ya / kan', 'Partikel akhir mencari persetujuan/konfirmasi.', ARRAY['partikel-akhir']::text[], '[{"sentence":"いい天気ですね。","hiragana":"いいてんきですね。","meaning":"Cuacanya bagus ya."},{"sentence":"そうですね。","hiragana":"そうですね。","meaning":"Begitu ya."}]'::jsonb, 16),
(1, '～よ', '~yo', 'lho / kok', 'Partikel akhir menegaskan informasi baru kepada lawan bicara.', ARRAY['partikel-akhir']::text[], '[{"sentence":"それは違いますよ。","hiragana":"それはちがいますよ。","meaning":"Itu salah lho."},{"sentence":"美味しいですよ。","hiragana":"おいしいですよ。","meaning":"Enak lho."}]'::jsonb, 17),
(1, '～が好きです', '~ga suki desu', 'suka ~', 'Menyatakan kesukaan. 好き adalah na-adjective.', ARRAY['kesukaan']::text[], '[{"sentence":"音楽が好きです。","hiragana":"おんがくがすきです。","meaning":"Saya suka musik."},{"sentence":"日本語が好きですか。","hiragana":"にほんごがすきですか。","meaning":"Apakah kamu suka bahasa Jepang?"}]'::jsonb, 18),
(1, '～が嫌いです', '~ga kirai desu', 'benci/tidak suka ~', 'Menyatakan ketidaksukaan.', ARRAY['kesukaan']::text[], '[{"sentence":"納豆が嫌いです。","hiragana":"なっとうがきらいです。","meaning":"Saya tidak suka natto."},{"sentence":"勉強が嫌いです。","hiragana":"べんきょうがきらいです。","meaning":"Saya tidak suka belajar."}]'::jsonb, 19),
(1, '～が上手です', '~ga jouzu desu', 'pandai/mahir ~', 'Menyatakan kemahiran seseorang dalam sesuatu.', ARRAY['kemampuan']::text[], '[{"sentence":"彼は料理が上手です。","hiragana":"かれはりょうりがじょうずです。","meaning":"Dia pandai memasak."},{"sentence":"歌が上手ですね。","hiragana":"うたがじょうずですね。","meaning":"Pandai menyanyi ya."}]'::jsonb, 20),
(1, '～が下手です', '~ga heta desu', 'tidak pandai ~', 'Menyatakan ketidakmampuan dalam sesuatu.', ARRAY['kemampuan']::text[], '[{"sentence":"私は絵が下手です。","hiragana":"わたしはえがへたです。","meaning":"Saya tidak pandai menggambar."},{"sentence":"運転が下手です。","hiragana":"うんてんがへたです。","meaning":"Tidak pandai menyetir."}]'::jsonb, 21),
(1, '～があります', '~ga arimasu', 'ada ~ (benda)', 'Menyatakan keberadaan benda mati.', ARRAY['keberadaan']::text[], '[{"sentence":"机の上に本があります。","hiragana":"つくえのうえにほんがあります。","meaning":"Ada buku di atas meja."},{"sentence":"時間がありますか。","hiragana":"じかんがありますか。","meaning":"Apakah ada waktu?"}]'::jsonb, 22),
(1, '～がいます', '~ga imasu', 'ada ~ (makhluk hidup)', 'Menyatakan keberadaan makhluk hidup.', ARRAY['keberadaan']::text[], '[{"sentence":"庭に猫がいます。","hiragana":"にわにねこがいます。","meaning":"Ada kucing di halaman."},{"sentence":"兄弟がいますか。","hiragana":"きょうだいがいますか。","meaning":"Apakah punya saudara?"}]'::jsonb, 23),
(1, '～をください', '~wo kudasai', 'tolong berikan ~', 'Meminta sesuatu dengan sopan.', ARRAY['permintaan']::text[], '[{"sentence":"水をください。","hiragana":"みずをください。","meaning":"Tolong air."},{"sentence":"これを二つください。","hiragana":"これをふたつください。","meaning":"Tolong dua ini."}]'::jsonb, 24),
(1, 'Verb て-form + ください', '~te kudasai', 'tolong lakukan ~', 'Meminta lawan bicara melakukan sesuatu.', ARRAY['permintaan','te-form']::text[], '[{"sentence":"ここに名前を書いてください。","hiragana":"ここになまえをかいてください。","meaning":"Tolong tulis nama di sini."},{"sentence":"ちょっと待ってください。","hiragana":"ちょっとまってください。","meaning":"Tolong tunggu sebentar."}]'::jsonb, 25),
(1, '～ませんか', '~masen ka', 'maukah ~? / bagaimana kalau ~?', 'Mengajak melakukan sesuatu dengan sopan.', ARRAY['ajakan']::text[], '[{"sentence":"一緒に行きませんか。","hiragana":"いっしょにいきませんか。","meaning":"Maukah pergi bersama?"},{"sentence":"お茶を飲みませんか。","hiragana":"おちゃをのみませんか。","meaning":"Bagaimana kalau minum teh?"}]'::jsonb, 26),
(1, '～ましょう', '~mashou', 'ayo ~', 'Mengajak/menawarkan untuk melakukan sesuatu bersama.', ARRAY['ajakan']::text[], '[{"sentence":"始めましょう。","hiragana":"はじめましょう。","meaning":"Ayo mulai."},{"sentence":"一緒に食べましょう。","hiragana":"いっしょにたべましょう。","meaning":"Ayo makan bersama."}]'::jsonb, 27),
(1, '～ましょうか', '~mashou ka', 'haruskah saya ~?', 'Menawarkan bantuan atau bertanya tentang ajakan.', ARRAY['ajakan','tawaran']::text[], '[{"sentence":"手伝いましょうか。","hiragana":"てつだいましょうか。","meaning":"Mau saya bantu?"},{"sentence":"窓を開けましょうか。","hiragana":"まどをあけましょうか。","meaning":"Saya buka jendelanya?"}]'::jsonb, 28),
(1, 'Verb-たい', '~tai', 'ingin ~', 'Menyatakan keinginan pembicara untuk melakukan sesuatu.', ARRAY['keinginan']::text[], '[{"sentence":"日本へ行きたいです。","hiragana":"にほんへいきたいです。","meaning":"Saya ingin pergi ke Jepang."},{"sentence":"何が食べたいですか。","hiragana":"なにがたべたいですか。","meaning":"Ingin makan apa?"}]'::jsonb, 29),
(1, '～が欲しいです', '~ga hoshii desu', 'ingin (memiliki) ~', 'Menyatakan keinginan memiliki suatu benda.', ARRAY['keinginan']::text[], '[{"sentence":"新しい車が欲しいです。","hiragana":"あたらしいくるまがほしいです。","meaning":"Saya ingin mobil baru."},{"sentence":"何が欲しいですか。","hiragana":"なにがほしいですか。","meaning":"Ingin apa?"}]'::jsonb, 30),
(1, '～ないでください', '~naide kudasai', 'tolong jangan ~', 'Meminta lawan bicara untuk tidak melakukan sesuatu.', ARRAY['permintaan','negatif']::text[], '[{"sentence":"写真を撮らないでください。","hiragana":"しゃしんをとらないでください。","meaning":"Tolong jangan foto."},{"sentence":"心配しないでください。","hiragana":"しんぱいしないでください。","meaning":"Tolong jangan khawatir."}]'::jsonb, 31),
(1, 'い-adjective + 名詞', 'i-keiyoushi', 'kata sifat-i + benda', 'Kata sifat-i langsung di depan kata benda tanpa perubahan.', ARRAY['kata-sifat']::text[], '[{"sentence":"大きい家。","hiragana":"おおきいいえ。","meaning":"Rumah besar."},{"sentence":"新しい車を買いました。","hiragana":"あたらしいくるまをかいました。","meaning":"Beli mobil baru."}]'::jsonb, 32),
(1, 'い-adjective 過去形', 'i-keiyoushi kako', 'kata sifat-i lampau', 'Bentuk lampau kata sifat-i: ～い → ～かった(です).', ARRAY['kata-sifat','lampau']::text[], '[{"sentence":"昨日は暑かったです。","hiragana":"きのうはあつかったです。","meaning":"Kemarin panas."},{"sentence":"映画は面白かったです。","hiragana":"えいがはおもしろかったです。","meaning":"Filmnya menarik."}]'::jsonb, 33),
(1, 'い-adjective 否定', 'i-keiyoushi hitei', 'kata sifat-i negatif', '～い → ～くないです.', ARRAY['kata-sifat','negatif']::text[], '[{"sentence":"この部屋は広くないです。","hiragana":"このへやはひろくないです。","meaning":"Kamar ini tidak luas."},{"sentence":"寒くないです。","hiragana":"さむくないです。","meaning":"Tidak dingin."}]'::jsonb, 34),
(1, 'な-adjective + 名詞', 'na-keiyoushi', 'kata sifat-na + benda', 'Kata sifat-na ditambah な sebelum kata benda.', ARRAY['kata-sifat']::text[], '[{"sentence":"きれいな花。","hiragana":"きれいなはな。","meaning":"Bunga yang indah."},{"sentence":"静かな町です。","hiragana":"しずかなまちです。","meaning":"Kota yang tenang."}]'::jsonb, 35),
(1, 'な-adjective + です', 'na-keiyoushi desu', 'kata sifat-na (predikat)', 'Kata sifat-na sebagai predikat memakai です.', ARRAY['kata-sifat']::text[], '[{"sentence":"この町は静かです。","hiragana":"このまちはしずかです。","meaning":"Kota ini tenang."},{"sentence":"彼は親切です。","hiragana":"かれはしんせつです。","meaning":"Dia baik hati."}]'::jsonb, 36),
(1, 'な-adjective 過去/否定', 'na-keiyoushi kako', 'kata sifat-na lampau/negatif', 'Lampau: ～でした. Negatif: ～じゃありません.', ARRAY['kata-sifat','lampau','negatif']::text[], '[{"sentence":"昨日は暇でした。","hiragana":"きのうはひまでした。","meaning":"Kemarin senggang."},{"sentence":"便利じゃありません。","hiragana":"べんりじゃありません。","meaning":"Tidak praktis."}]'::jsonb, 37),
(1, '～より～のほうが', '~yori ~no hou ga', '~ lebih ~ daripada ~', 'Membandingkan dua hal.', ARRAY['perbandingan']::text[], '[{"sentence":"犬より猫のほうが好きです。","hiragana":"いぬよりねこのほうがすきです。","meaning":"Lebih suka kucing daripada anjing."},{"sentence":"電車のほうが速いです。","hiragana":"でんしゃのほうがはやいです。","meaning":"Kereta lebih cepat."}]'::jsonb, 38),
(1, '～の中で～が一番', '~no naka de ~ga ichiban', 'di antara ~, ~ paling ~', 'Menyatakan superlatif dalam suatu kelompok.', ARRAY['perbandingan','superlatif']::text[], '[{"sentence":"果物の中でりんごが一番好きです。","hiragana":"くだもののなかでりんごがいちばんすきです。","meaning":"Dari buah-buahan paling suka apel."},{"sentence":"クラスで彼が一番背が高い。","hiragana":"くらすでかれがいちばんせがたかい。","meaning":"Di kelas dia paling tinggi."}]'::jsonb, 39),
(1, '～ことができます', '~koto ga dekimasu', 'bisa ~', 'Menyatakan kemampuan melakukan sesuatu.', ARRAY['kemampuan']::text[], '[{"sentence":"日本語を話すことができます。","hiragana":"にほんごをはなすことができます。","meaning":"Bisa berbicara bahasa Jepang."},{"sentence":"泳ぐことができますか。","hiragana":"およぐことができますか。","meaning":"Bisa berenang?"}]'::jsonb, 40),
(1, '～前に', '~mae ni', 'sebelum ~', 'Menyatakan urutan: melakukan A sebelum B.', ARRAY['waktu','urutan']::text[], '[{"sentence":"寝る前に歯を磨きます。","hiragana":"ねるまえにはをみがきます。","meaning":"Sebelum tidur sikat gigi."},{"sentence":"食事の前に手を洗います。","hiragana":"しょくじのまえにてをあらいます。","meaning":"Sebelum makan cuci tangan."}]'::jsonb, 41),
(1, '～後で', '~ato de', 'setelah ~', 'Menyatakan urutan: setelah A baru B.', ARRAY['waktu','urutan']::text[], '[{"sentence":"食事の後で散歩します。","hiragana":"しょくじのあとでさんぽします。","meaning":"Setelah makan jalan-jalan."},{"sentence":"宿題の後で遊びます。","hiragana":"しゅくだいのあとであそびます。","meaning":"Setelah PR baru main."}]'::jsonb, 42),
