(2, '～ている (keadaan/progres)', '~te iru', 'sedang/keadaan ~', 'Aksi berlangsung atau keadaan akibat aksi.', ARRAY['te-form','progresif']::text[], '[{"sentence":"今、ご飯を食べている。","hiragana":"いま、ごはんをたべている。","meaning":"Sekarang sedang makan."},{"sentence":"窓が開いている。","hiragana":"まどがあいている。","meaning":"Jendelanya terbuka."}]'::jsonb, 1),
